using System; using System.Collections.Generic; using System.Configuration; using dk.gi.app.ejendom.tjekejerskifte.Application.Models;
namespace dk.gi.app.ejendom.tjekejerskifte.Infrastructure.Config
{ public static class EjendomTjekEjerskifteSettingsValidator { public static void Validate(EjendomTjekEjerskifteSettings settings) { if (settings == null) throw new ArgumentNullException(nameof(settings)); var missing = new List<string>(); if (string.IsNullOrWhiteSpace(settings.Mode)) missing.Add("Mode"); if (settings.MaxDage < 0) throw new ConfigurationErrorsException("MaxDage må ikke være negativ."); if (settings.MaxAntal <= 0) throw new ConfigurationErrorsException("MaxAntal skal være større end 0."); if (settings.MaxAntal >= 5000) throw new ConfigurationErrorsException("MaxAntal må ikke være over 4999."); if (string.IsNullOrWhiteSpace(settings.CrmConnectionTemplate)) missing.Add("CrmConnectionTemplate"); if (string.IsNullOrWhiteSpace(settings.CrmServerName)) missing.Add("CrmServerName"); if (string.IsNullOrWhiteSpace(settings.CrmClientId)) missing.Add("CrmClientId"); if (string.IsNullOrWhiteSpace(settings.CrmClientSecret)) missing.Add("CrmClientSecret"); if (string.IsNullOrWhiteSpace(settings.CrmAuthority)) missing.Add("CrmAuthority"); if (string.IsNullOrWhiteSpace(settings.ServiceBusQueueName)) missing.Add("ServiceBusQueueName"); if (string.IsNullOrWhiteSpace(settings.ServiceBusLabel)) missing.Add("ServiceBusLabel"); if (missing.Count > 0) throw new ConfigurationErrorsException("Følgende settings mangler til valgt mode: " + string.Join(", ", missing)); } } }
